import os
from collections import defaultdict
from biothings_client import get_client
import re

from csv import DictReader
from biothings.utils.dataload import dict_sweep, open_anyfile, unlist, value_convert_to_number


def batch_query_hgvs_from_rsid(rsid_list):
    hgvs_rsid_dict = {}
    print('total rsids: {}'.format(len(rsid_list)))
    rsid_list = list(set(rsid_list))
    variant_client = get_client('variant')
    for i in range(0, len(rsid_list), 1000):
        if i + 1000 <= len(rsid_list):
            batch = rsid_list[i: i+1000]
        else:
            batch = rsid_list[i:]
        params = ','.join(batch)
        res = variant_client.getvariants(params, fields="_id")
        print("currently processing {}th variant".format(i))
        for _doc in res:
            if '_id' not in _doc:
                print('can not convert', _doc)
            hgvs_rsid_dict[_doc['query']] = _doc['_id'] if '_id' in _doc else _doc["query"]
    return hgvs_rsid_dict


def load_data(data_folder):

    input_file = os.path.join(data_folder, "phewas-catalog.csv")
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Can't find input file '{input_file}'")
    with open_anyfile(input_file) as in_f:

        # Remove duplicated lines if any
        header = next(in_f).strip().split(',')
        header = [_item[1:-1] for _item in header]
        lines = set(list(in_f))
        reader = DictReader(lines, fieldnames=header, delimiter=',')

        results = defaultdict(list)
        for row in reader:
            variant = {"associations": {"phenotype": {}}, "variant": {}}
            if not re.match("^rs\d+$", row["snp"]):
                raise ValueError(f"Invalid SNP format: {row['snp']}")
            variant["variant"]["rsid"] = row["snp"]
            variant["associations"]["phenotype"]["name"] = row["phewas phenotype"]
            variant["associations"]["cases"] = row["cases"]

            variant["associations"]["pval"] = float(row["p-value"])
            variant["associations"]["odds-ratio"] = row["odds-ratio"]
            variant["associations"]["phenotype"]["phewas_code"] = row["phewas code"]
            variant["variant"]["gene"] = row["gene_name"]
            variant["variant"]["gwas_associations"] = row["gwas-associations"].split(',')
            pos_info = row["chromosome"].split(' ')
            if len(pos_info) == 2:
                variant["variant"]["chrom"], variant["variant"]["pos"] = pos_info
            else:
                variant["variant"]["chrom"] = pos_info[0]
            results[variant["variant"]["rsid"]].append(variant)
        # Merge duplications
        rsid_list = [_item for _item in results.keys()]
        hgvs_rsid_dict = batch_query_hgvs_from_rsid(rsid_list)
        for k, v in results.items():
            if k in hgvs_rsid_dict and hgvs_rsid_dict[k]:
                if len(v) == 1:
                    doc = {'_id': hgvs_rsid_dict[k],
                           'phewas': v[0]["variant"]}
                    doc["phewas"]["associations"] = v[0]["associations"]
                    yield dict_sweep(unlist(value_convert_to_number(doc, skipped_keys=['chrom'])), vals=[[], {}, None, '', 'NULL'])
                else:
                    doc = {'_id': hgvs_rsid_dict[k],
                           'phewas': v[0]["variant"]}
                    doc["phewas"]["associations"] = []
                    for _item in v:
                        doc["phewas"]["associations"].append(_item["associations"])
                    yield dict_sweep(unlist(value_convert_to_number(doc, skipped_keys=['chrom'])), vals=[[], {}, None, '', 'NULL'])

"""
Uploader for the pubtator3 data plugin

Handles the parsing of the documents provided by [relation2pubtator3.gz]
"""

import itertools
from pathlib import Path
from typing import Union
import gzip

import biothings
from biothings import config
import biothings.hub.dataload.uploader


logger = config.logger


class Pubtator3Uploader(biothings.hub.dataload.uploader.IgnoreDuplicatedSourceUploader):
    name = "pubtator3"
    __metadata__ = {
        "src_meta": {
            "url": "https://www.ncbi.nlm.nih.gov/research/pubtator3/",
            "license_url": "https://www.ncbi.nlm.nih.gov/home/about/policies/",
            "description": "Search entities & relations in 35+ million biomedical publications.",
        }
    }

    def load_data(self, data_folder: Union[str, Path]):
        """
        We have multiple different instances for entries

        instance 1: [MESH ID]
        >>> 33846804	treat	Chemical|MESH:D009828	Disease|MESH:D006528

        instance 2: [GENE ID]
        >>> 33846805	associate	Gene|5289	Gene|5562

        instance3: [MULTIPLE]
        >>> 26018198	associate	ProteinMutation|RS#:121908192;HGVS:c.581G>A;CorrespondingGene:2671	ProteinMutation|RS#:771809901;HGVS:c.373C>T;CorrespondingGene:2671
        >>> 20817350        cause   Disease|MESH:D000544    ProteinMutation|RS#:1800562;CorrespondingGene:3077
        """
        download_file_name = "relation2pubtator3.gz"
        unstructured_relational_datafile = Path(data_folder).joinpath(download_file_name)
        unstructured_relational_datafile = unstructured_relational_datafile.resolve().absolute()
        with gzip.open(unstructured_relational_datafile, "rb", compresslevel=9) as file_handle:
            column_delimiter = "\t"
            entity_delimiter = "|"
            identifier_delimiter = ";"
            value_delimiter = ":"

            while True:
                entry = file_handle.readline()
                if entry == b"":
                    break

                entry_collection = entry.decode("utf-8").strip().split(column_delimiter)
                pmid = int(entry_collection[0])
                predicate = str(entry_collection[1]).upper()
                object_concept = str(entry_collection[2])
                subject_concept = str(entry_collection[3])

                object_entity_type, __, object_id = object_concept.partition(entity_delimiter)
                subject_entity_type, __, subject_id = subject_concept.partition(entity_delimiter)

                object_id_collection = object_id.split(identifier_delimiter)
                subject_id_collection = subject_id.split(identifier_delimiter)

                objects = []
                object_values = []
                subjects = []
                subject_values = []
                for object_id, subject_id in itertools.zip_longest(
                    object_id_collection, subject_id_collection, fillvalue=None
                ):
                    if object_id is not None:
                        sub_object_id = object_id.split(value_delimiter)
                        match len(sub_object_id):
                            case 1:
                                object_identifer_key = None
                                object_identifer_value = sub_object_id[0]
                            case 2:
                                object_identifer_key = sub_object_id[0]
                                object_identifer_value = sub_object_id[1]

                        objects.append(
                            {
                                "semantic_type_name": object_entity_type,
                                "identifier": {"key": object_identifer_key, "value": object_identifer_value},
                            }
                        )
                        object_values.append(object_identifer_value)

                    if subject_id is not None:
                        sub_subject_id = subject_id.split(value_delimiter)
                        match len(sub_subject_id):
                            case 1:
                                subject_identifier_key = None
                                subject_identifier_value = sub_subject_id[0]

                            case 2:
                                subject_identifier_key = sub_subject_id[0]
                                subject_identifier_value = sub_subject_id[1]

                        subjects.append(
                            {
                                "semantic_type_name": subject_entity_type,
                                "identifier": {"key": subject_identifier_key, "value": subject_identifier_value},
                            }
                        )
                        subject_values.append(subject_identifier_value)

                unique_id = f"{pmid}-{object_concept}-{predicate}-{subject_concept}"

                if len(objects) == 1:
                    objects = objects[0]
                if len(subjects) == 1:
                    subjects = subjects[0]

                document = {
                    "_id": unique_id,
                    "object": objects,
                    "pmid_count": 1,
                    "predicate": predicate,
                    "predication_count": 1,
                    "pmid": pmid,
                    "subject": subjects,
                }
                yield document

    @classmethod
    def get_mapping(self) -> dict:
        mapping = {
            "object": {
                "properties": {
                    "semantic_type_name": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                    "identifier": {
                        "properties": {
                            "key": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                            "value": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                        }
                    },
                }
            },
            "pmid_count": {"type": "integer"},
            "predicate": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
            "predication_count": {"type": "integer"},
            "pmid": {"type": "integer"},
            "subject": {
                "properties": {
                    "semantic_type_name": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                    "identifier": {
                        "properties": {
                            "key": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                            "value": {"normalizer": "keyword_lowercase_normalizer", "type": "keyword"},
                        }
                    },
                }
            },
        }

        return mapping

from collections import defaultdict
import networkx as nx
import obonet
import os
import re

def get_synonyms(data):
    """Format synonyms as a dictionary.
    Exact and related synonyms are the keys, and their values are lists.
    """
    synonyms = defaultdict(list)
    for syn in data.get('synonym', []):
        match = re.findall(r'\"(.+?)\"', syn)
        if 'EXACT' in syn:
            synonyms["exact"].extend(match)
        elif 'RELATED' in syn:
            synonyms["related"].extend(match)
    return dict(synonyms)

def load_ontology_data(data_folder):
    path = os.path.join(data_folder, "uberon.obo")
    graph = obonet.read_obo(path)
    return graph

def process_node(graph, item):
    rec = graph.nodes[item]
    rec["_id"] = item
    rec["uberon"] = item
    if rec.get("is_a"):
        rec["parents"] = [parent for parent in rec.pop("is_a") if parent.startswith("UBERON:")]
    if rec.get("xref"):
        rec["xrefs"] = process_xrefs(rec.pop("xref"))
    rec["children"] = [child for child in graph.predecessors(item) if child.startswith("UBERON:")]
    rec["ancestors"] = [ancestor for ancestor in nx.descendants(graph, item) if ancestor.startswith("UBERON:")]
    rec["descendants"] = [descendant for descendant in nx.ancestors(graph, item) if descendant.startswith("UBERON:")]
    rec["synonym"] = get_synonyms(rec)
    remove_unnecessary_fields(rec)
    process_relationships(rec)
    return rec

def process_xrefs(xref_list):
    xrefs = defaultdict(list)
    for val in xref_list:
        if ":" in val:
            prefix, idx = val.split(':', 1)
            if prefix.lower() in ['umls', 'mesh']:
                xrefs[prefix.lower()].append(idx)
            elif prefix == 'EFO':
                xrefs[prefix.lower()].append(val)
    return dict(xrefs)

def remove_unnecessary_fields(rec):
    fields_to_remove = ["created_by", "creation_date", "property_value", "relationship"]
    for field in fields_to_remove:
        rec.pop(field, None)

def process_relationships(rec):
    if rec.get("relationship"):
        rels = {}
        for rel in rec.get("relationship"):
            predicate, val = rel.split(' ')
            prefix = val.split(':')[0]
            if predicate not in rels:
                rels[predicate] = defaultdict(set)
            if prefix.lower() not in rels[predicate]:
                rels[predicate][prefix.lower()].add(val)
        for m, n in rels.items():
            for p, q in n.items():
                n[p] = list(q)
            rels[m] = dict(n)
        rec.update(rels)
        rec.pop("relationship")

def load_data(data_folder):
    graph = load_ontology_data(data_folder)
    for item in graph.nodes():
        if item.startswith("UBERON:"):
            rec = process_node(graph, item)
            yield rec

